// LESSON: Reference Page 1 - Komposition och design.
// You will learn: Use composition, single responsibility, and strategy interfaces.
class Prog2Reference427 {
  // EXEMPEL 1: Komposition betyder att ett objekt byggs av andra objekt.
  static class Engine {
    void start() { System.out.println("start"); }
  }
  static class Car {
    private final Engine engine;
    Car(Engine engine) { this.engine = engine; }
    void drive() { engine.start(); }
  }
  // EXEMPEL 2: Single Responsibility delar upp ansvar i sma klasser.
  static class PriceCalculator {
    int total(int price, int count) { return price * count; }
  }
  static class ReceiptPrinter {
    String line(String name, int total) { return name + ":" + total; }
  }
  // EXEMPEL 3: Strategy byter beteende via ett interface.
  interface DiscountPolicy {
    int discount(int price);
  }
  static class NoDiscount implements DiscountPolicy {
    public int discount(int price) { return 0; }
  }
  static int finalPrice(int price, DiscountPolicy policy) {
    return price - policy.discount(price);
  }
}
